var mw = RulesEngine.get_unit_weapons("U_TC_BOYZ", GameState.state)
var sl = 0
var ghost = 0
for mid in mw:
	for w in mw[mid]:
		if str(w).begins_with("slugga"): sl += 1
		elif str(w).begins_with("big_shoota") or str(w).begins_with("rokkit") or str(w).begins_with("shoota") or str(w).begins_with("kombi"): ghost += 1
return "%d_slugga_%d_ghost" % [sl, ghost]

var mw = RulesEngine.get_unit_weapons("U_TC_BOYZ", GameState.state)
var t = 0
for mid in mw:
	t += mw[mid].size()
return t

var mw = RulesEngine.get_unit_weapons("U_TC_DEFF", GameState.state)
var kr = 0
var sl = 0
var t = 0
for mid in mw:
	t += mw[mid].size()
	for w in mw[mid]:
		if str(w).begins_with("kopta_rokkits"): kr += 1
		elif str(w).begins_with("slugga"): sl += 1
return "%d_kopta_%d_slugga_%d_total" % [kr, sl, t]
